#include <stdio.h>
#include <stdint.h>
#include <string.h>

/*
 * Memory Location and Addresses - C Implementation
 * Demonstrates pointers, memory addresses, and endianness
 */

/* Structure to hold address calculation results */
typedef struct {
 int address_bits;
 uint64_t total_addresses;
 uint64_t total_bytes;
 char readable[64];
} AddressSpace;


/* Calculate addressable memory space for given address bus width */
void calculate_address_space(int bits, AddressSpace *result) {
 result->address_bits = bits;
 result->total_addresses = (uint64_t)1 << bits; // 2^bits
 result->total_bytes = result->total_addresses; // Byte-addressable

 // Format readable output
 if (result->total_bytes >= 1024ULL * 1024 * 1024) {
 double gb = (double)result->total_bytes / (1024.0 * 1024.0 * 1024.0);
 sprintf(result->readable, "%.2f GB", gb);
 } else if (result->total_bytes >= 1024ULL * 1024) {
 double mb = (double)result->total_bytes / (1024.0 * 1024.0);
 sprintf(result->readable, "%.2f MB", mb);
 } else if (result->total_bytes >= 1024ULL) {
 double kb = (double)result->total_bytes / 1024.0;
 sprintf(result->readable, "%.2f KB", kb);
 } else {
 sprintf(result->readable, "%llu bytes", result->total_bytes);
 }
}


/* Check system endianness */
int is_little_endian(void) {
 uint32_t test = 0x00000001;
 uint8_t *byte_ptr = (uint8_t *)&test;
 // If first byte is 1, system is little-endian (LSB at lowest address)
 return byte_ptr[0] == 0x01;
}


/* Print memory layout of a 32-bit value */
void print_memory_bytes(uint32_t value, uintptr_t base_address) {
 uint8_t *bytes = (uint8_t *)&value;

 printf("Memory layout of 0x%08X at base address %lu:\n", value, (unsigned long)base_address);
 printf(" Address %lu: 0x%02X (byte 0, LSB)\n", 
 (unsigned long)(base_address), bytes[0]);
 printf(" Address %lu: 0x%02X (byte 1)\n", 
 (unsigned long)(base_address + 1), bytes[1]);
 printf(" Address %lu: 0x%02X (byte 2)\n", 
 (unsigned long)(base_address + 2), bytes[2]);
 printf(" Address %lu: 0x%02X (byte 3, MSB)\n", 
 (unsigned long)(base_address + 3), bytes[3]);
}


/* Demonstrate pointer arithmetic and memory addressing */
void demonstrate_pointers(void) {
 int array[5] = {100, 200, 300, 400, 500};
 int *ptr = array;

 printf("\nPointer Arithmetic Demonstration:\n");
 printf("Array base address: %p\n", (void *)array);
 printf("Size of int: %zu bytes\n\n", sizeof(int));

 for (int i = 0; i < 5; i++) {
 printf("array[%d] at address %p: value = %d\n", 
 i, (void *)(ptr + i), *(ptr + i));
 }
}


/* Demonstrate byte-level memory access */
void demonstrate_byte_access(void) {
 uint32_t value = 0x0A0B0C0D;
 uint8_t *byte_ptr = (uint8_t *)&value;

 printf("\nByte-Level Memory Access:\n");
 printf("Variable 'value' (uint32_t): 0x%08X\n", value);
 printf("Individual bytes (from lowest address):\n");
 for (int i = 0; i < 4; i++) {
 printf(" byte_ptr[%d] = 0x%02X\n", i, byte_ptr[i]);
 }
}


int main(void) {
 printf("============================================================\n");
 printf("MEMORY LOCATION AND ADDRESSES - C IMPLEMENTATION\n");
 printf("============================================================\n");

 /* 1. Address Space Calculations */
 printf("\n1. ADDRESS SPACE CALCULATIONS\n");
 printf("----------------------------------------\n");

 int test_bits[] = {8, 16, 20, 32, 64};
 AddressSpace result;

 for (int i = 0; i < 5; i++) {
 calculate_address_space(test_bits[i], &result);
 printf("\n%d-bit address bus:\n", result.address_bits);
 printf(" Total addresses: 2^%d = %llu\n", 
 result.address_bits, (unsigned long long)result.total_addresses);
 printf(" Addressable memory: %s\n", result.readable);
 }

 /* 2. System Endianness */
 printf("\n\n2. SYSTEM ENDIANNESS\n");
 printf("----------------------------------------\n");

 if (is_little_endian()) {
 printf("System is Little-Endian\n");
 printf("(Most common: Intel x86, x86-64)\n");
 } else {
 printf("System is Big-Endian\n");
 }

 /* 3. Memory Byte Layout */
 printf("\n\n3. MEMORY BYTE LAYOUT DEMONSTRATION\n");
 printf("----------------------------------------\n");

 uint32_t test_value = 0x0A0B0C0D;
 print_memory_bytes(test_value, (uintptr_t)1000);

 /* 4. Pointer Demonstration */
 demonstrate_pointers();

 /* 5. Byte Access */
 demonstrate_byte_access();

 printf("\n============================================================\n");
 return 0;
}
